# frozen_string_literal: true

# ================================================================
# Tests for MosaicReactRenderer
# ================================================================
#
# The React renderer emits TypeScript TSX functional components.
# We run it end-to-end (source → analyze → VM → renderer → TSX)
# and check the generated file content.
# ================================================================

require "minitest/autorun"
require "coding_adventures_mosaic_analyzer"
require "coding_adventures_mosaic_vm"
require "coding_adventures_mosaic_emit_react"

class TestMosaicEmitReact < Minitest::Test
  MA  = CodingAdventures::MosaicAnalyzer
  VM  = CodingAdventures::MosaicVm::MosaicVM
  RR  = CodingAdventures::MosaicEmitReact::ReactRenderer

  # ----------------------------------------------------------------
  # Helper: generate TSX from source
  # ----------------------------------------------------------------

  def generate(source)
    ir = MA.analyze(source)
    vm = VM.new(ir)
    result = vm.run(RR.new)
    result
  end

  def tsx(source)
    generate(source)[:files][0][:content]
  end

  # ----------------------------------------------------------------
  # Version
  # ----------------------------------------------------------------

  def test_version_exists
    refute_nil CodingAdventures::MosaicEmitReact::VERSION
  end

  # ----------------------------------------------------------------
  # Output structure
  # ----------------------------------------------------------------

  def test_emit_returns_files_array
    result = generate("component Label { Text { } }")
    assert_includes result, :files
    assert_equal 1, result[:files].length
  end

  def test_filename_is_component_name_tsx
    result = generate("component ProfileCard { Text { } }")
    assert_equal "ProfileCard.tsx", result[:files][0][:filename]
  end

  def test_file_content_is_string
    content = tsx("component Label { Text { } }")
    assert_kind_of String, content
  end

  # ----------------------------------------------------------------
  # File header
  # ----------------------------------------------------------------

  def test_autogenerated_header
    content = tsx("component Label { Text { } }")
    assert_includes content, "AUTO-GENERATED"
  end

  def test_react_import
    content = tsx("component Label { Text { } }")
    assert_includes content, 'import React from "react"'
  end

  # ----------------------------------------------------------------
  # Props interface
  # ----------------------------------------------------------------

  def test_props_interface_generated
    content = tsx("component C { slot title: text; Text { } }")
    assert_includes content, "interface CProps {"
  end

  def test_slot_appears_in_props
    content = tsx("component C { slot title: text; Text { } }")
    assert_includes content, "title: string"
  end

  def test_optional_slot_has_question_mark
    content = tsx("component C { slot count: number = 0; Text { } }")
    assert_includes content, "count?"
  end

  def test_bool_slot_type
    content = tsx("component C { slot visible: bool; Text { } }")
    assert_includes content, "visible: boolean"
  end

  def test_node_slot_type
    content = tsx("component C { slot content: node; Text { } }")
    assert_includes content, "content: React.ReactNode"
  end

  def test_list_slot_type
    content = tsx("component C { slot items: list<text>; Text { } }")
    assert_includes content, "items: string[]"
  end

  # ----------------------------------------------------------------
  # Function component
  # ----------------------------------------------------------------

  def test_function_component_generated
    content = tsx("component Label { Text { } }")
    assert_includes content, "export function Label("
  end

  def test_function_uses_props_interface
    content = tsx("component Label { slot title: text; Text { } }")
    assert_includes content, "LabelProps"
  end

  def test_function_return_has_jsx
    content = tsx("component C { Text { } }")
    assert_includes content, "return ("
  end

  # ----------------------------------------------------------------
  # JSX generation
  # ----------------------------------------------------------------

  def test_column_maps_to_div
    content = tsx("component C { Column { } }")
    assert_includes content, "<div"
  end

  def test_text_maps_to_span
    content = tsx("component C { Text { } }")
    assert_includes content, "<span"
  end

  def test_image_maps_to_img
    content = tsx("component C { Image { } }")
    assert_includes content, "<img"
  end

  def test_content_property_as_text_content
    content = tsx('component C { Text { content: "hello"; } }')
    assert_includes content, "hello"
  end

  # ----------------------------------------------------------------
  # Color rendering
  # ----------------------------------------------------------------

  def test_color_rendered_as_rgba
    content = tsx("component C { Column { background: #2563eb; } }")
    assert_includes content, "rgba("
    assert_includes content, "backgroundColor"
  end

  # ----------------------------------------------------------------
  # Dimension rendering
  # ----------------------------------------------------------------

  def test_dimension_dp_to_px
    content = tsx("component C { Column { padding: 16dp; } }")
    assert_includes content, "16px"
    assert_includes content, "padding"
  end

  # ----------------------------------------------------------------
  # when blocks
  # ----------------------------------------------------------------

  def test_when_block_generates_conditional
    source = <<~MOSAIC
      component C {
        slot show: bool;
        Column { when @show { Text { } } }
      }
    MOSAIC
    content = tsx(source)
    assert_includes content, "show &&"
  end

  # ----------------------------------------------------------------
  # each blocks
  # ----------------------------------------------------------------

  def test_each_block_generates_map
    source = <<~MOSAIC
      component List {
        slot items: list<text>;
        Column { each @items as item { Text { } } }
      }
    MOSAIC
    content = tsx(source)
    assert_includes content, "items.map("
    assert_includes content, "item"
  end
end
